sys_ux_client_script_include.script:
function include({imports}) {

    function nfIsDataField(field) {
        return field.isDataField !== false;
    }

    function nfIsFieldReadonly(field) {
        return field.readonly === true || field.sys_readonly === true;
    }

    function nfValIsEmpty(field, value) {
        if (value === null || value === undefined) {
            return true;
        }
        var t = field.type || field.internalType || '';
        if (t === 'boolean' || field.internalType === 'boolean') {
            return false;
        }
        if (typeof value === 'string' && value.trim() === '') {
            return true;
        }
        return false;
    }

    function nfValidateOneField(field) {
        if (!nfIsDataField(field)) {
            return { ok: true, message: null };
        }
        if (nfIsFieldReadonly(field)) {
            return { ok: true, message: null };
        }
        var rule = field.nfValidation || null;
        var value = field.value;
        var mandatory = rule ? (rule.mandatory === true) : (field.mandatory === true);
        var empty = nfValIsEmpty(field, value);
        if (mandatory && empty) {
            return { ok: false, message: 'This field is required' };
        }
        if (empty) {
            return { ok: true, message: null };
        }
        var strVal = String(value);
        if (rule) {
            if (rule.readOnly === true) {
                return { ok: true, message: null };
            }
            if (rule.minLength != null && !isNaN(rule.minLength)) {
                if (strVal.length < Number(rule.minLength)) {
                    return { ok: false, message: 'Value is too short' };
                }
            }
            if (rule.maxLength != null && !isNaN(rule.maxLength)) {
                if (strVal.length > Number(rule.maxLength)) {
                    return { ok: false, message: 'Value is too long' };
                }
            }
            if (Array.isArray(rule.allowedValues) && rule.allowedValues.length) {
                var okAv = false;
                for (var i = 0; i < rule.allowedValues.length; i++) {
                    var av = rule.allowedValues[i];
                    if (String(av) === strVal || av === value) {
                        okAv = true;
                        break;
                    }
                }
                if (!okAv) {
                    return { ok: false, message: 'Value is not an allowed choice' };
                }
            }
            if (typeof rule.regexPattern === 'string' && rule.regexPattern.length) {
                try {
                    var re = new RegExp(rule.regexPattern);
                    if (!re.test(strVal)) {
                        return { ok: false, message: 'Value does not match the required pattern' };
                    }
                } catch (e0) {
                    return { ok: false, message: 'Invalid validation pattern' };
                }
            }
            var typ = (rule.type || 'string').toLowerCase();
            if (typ === 'integer' || typ === 'int' || typ === 'long') {
                if (!/^-?\d+$/.test(strVal)) {
                    return { ok: false, message: 'Enter a whole number' };
                }
            } else if (typ === 'decimal' || typ === 'float' || typ === 'numeric' || typ === 'currency') {
                if (!/^-?\d+(\.\d+)?$/.test(strVal)) {
                    return { ok: false, message: 'Enter a valid number' };
                }
            }
        }
        return { ok: true, message: null };
    }

    function nfRevalidateAllFields(fields) {
        var out = {};
        var allOk = true;
        Object.keys(fields).forEach(function (key) {
            var field = fields[key];
            var result = nfValidateOneField(field);
            if (!result.ok) {
                allOk = false;
            }
            var next = Object.assign({}, field);
            if (result.message) {
                next.messages = [{ messageType: 'error', message: result.message }];
                next.nfValidationMessage = result.message;
            } else {
                delete next.messages;
                delete next.nfValidationMessage;
            }
            out[key] = next;
        });
        return { fields: out, allOk: allOk };
    }

    return {
        nfRevalidateAllFields: nfRevalidateAllFields
    };
}
